export const documentPromptMap: DocumentPromptEntry[] = documents.map((document) => ({
  title: document.title,
  summary: document.terminalSummary,
  link: document.path,
  triggers: document.keywords,
}));

export const terminalDocumentContext = documentPromptMap
  .map(
    (document) =>
      `SUMMARY: ${document.summary} | LINK: ${document.link} | TRIGGERS: ${document.triggers.join(', ')}`
  )
  .join('\n');

export const findDocumentByPath = (path: string | undefined) => {
  const requestedPath = `/documents/${path ?? ''}`.replace(/\/+$/, '').toLowerCase();
  return documents.find((document) => document.path.toLowerCase() === requestedPath);
};
